     2→ * Encryption Service for API Keys
     3→ * Uses WebCrypto API for AES-256-GCM encryption with PBKDF2 key derivation
     4→ * Provides secure, password-based encryption for sensitive data
     5→ *
     6→ * MIGRATION NOTE: This file now uses WebCrypto API instead of crypto-js
     7→ * - All functions are now async (use await)
     8→ * - Provides backward compatibility for old crypto-js encrypted data
     9→ */
    10→
    11→import * as WebCrypto from './encryptionWebCrypto';
    12→import CryptoJS from 'crypto-js'; // Keep for backward compatibility with old encrypted data
    13→
    14→/**
    15→ * Encryption configuration constants
    16→ */
    17→const ENCRYPTION_CONFIG = {
    18→  iterations: 100000, // PBKDF2 iterations (100k recommended minimum)
    19→  keySize: 256 / 32, // 256-bit key
    20→  algorithm: 'AES',
    21→};
    22→
    23→/**
    24→ * Encrypted data structure
    25→ */
    26→export interface EncryptedData {
    27→  ciphertext: string;
    28→  salt: string;
    29→  iv: string;
    30→  version?: 'crypto-js' | 'webcrypto'; // Track encryption method for migration
    31→  pbkdf2Version?: number; // PBKDF2 iteration version (1=100k, 2=600k)
    32→}
    33→
    34→/**
    35→ * Derive encryption key from password using PBKDF2 (crypto-js - for backward compatibility)
    36→ * @param password - User's encryption password
    37→ * @param salt - Salt for key derivation
    38→ * @returns Derived encryption key
    39→ */
    40→function deriveKey(password: string, salt: string): CryptoJS.lib.WordArray {
    41→  return CryptoJS.PBKDF2(password, salt, {
    42→    keySize: ENCRYPTION_CONFIG.keySize,
    43→    iterations: ENCRYPTION_CONFIG.iterations,
    44→  });
    45→}
    46→
    47→/**
    48→ * Encrypt plaintext using AES-256-GCM (WebCrypto API)
    49→ * @param plaintext - Data to encrypt (e.g., API key)
    50→ * @param password - User's encryption password
    51→ * @returns Encrypted data with salt and IV
    52→ */
    53→export async function encrypt(plaintext: string, password: string): Promise<EncryptedData> {
    54→  const encrypted = await WebCrypto.encrypt(plaintext, password);
    55→  return {
    56→    ciphertext: encrypted.ciphertext,
    57→    salt: encrypted.salt,
    58→    iv: encrypted.iv,
    59→    version: 'webcrypto', // Mark as WebCrypto encrypted (vs crypto-js)
    60→    pbkdf2Version: encrypted.version, // PBKDF2 iteration version (2 = 600k iterations)
    61→  };
    62→}
    63→
    64→/**
    65→ * Decrypt ciphertext using AES-256-GCM (WebCrypto) or AES-256-CBC (crypto-js for backward compatibility)
    66→ * @param encryptedData - Encrypted data with salt and IV
    67→ * @param password - User's encryption password
    68→ * @returns Decrypted plaintext
    69→ * @throws Error if decryption fails (wrong password or corrupted data)
    70→ */
    71→export async function decrypt(encryptedData: EncryptedData, password: string): Promise<string> {
    72→  if (!encryptedData || !password) {
    73→    throw new Error('Encrypted data and password are required for decryption');
    74→  }
    75→
    76→  const { ciphertext, salt, iv, version, pbkdf2Version } = encryptedData;
    77→
    78→  if (!ciphertext || !salt || !iv) {
    79→    throw new Error('Invalid encrypted data structure');
    80→  }
    81→
    82→  // If encrypted with WebCrypto, use WebCrypto to decrypt
    83→  if (version === 'webcrypto') {
    84→    // Pass the PBKDF2 version for correct key derivation iterations
    85→    // Default to v2 (600k iterations) for webcrypto without explicit pbkdf2Version
    86→    // since all webcrypto encryptions use the current ENCRYPTION_CONFIG.version
    87→    return WebCrypto.decrypt({
    88→      ciphertext,
    89→      salt,
    90→      iv,
    91→      version: pbkdf2Version ?? 2, // Default to v2 for webcrypto
    92→    }, password);
