     1→/**
     2→ * Centralized Error Handling Service
     3→ * Provides consistent error handling patterns across the application
     4→ *
     5→ * Features:
     6→ * - Typed error categories for each domain
     7→ * - Error logging with context
     8→ * - User-friendly error messages
     9→ * - Error recovery suggestions
    10→ * - Development vs production error handling
    11→ */
    12→
    13→/**
    14→ * Error categories for different domains
    15→ */
    16→export const ErrorCategory = {
    17→  // Storage & Data
    18→  STORAGE: 'storage',
    19→  INDEXEDDB: 'indexeddb',
    20→  PERSISTENCE: 'persistence',
    21→
    22→  // AI & Providers
    23→  AI_PROVIDER: 'ai_provider',
    24→  AI_RATE_LIMIT: 'ai_rate_limit',
    25→  AI_QUOTA: 'ai_quota',
    26→  AI_NETWORK: 'ai_network',
    27→
    28→  // Security
    29→  ENCRYPTION: 'encryption',
    30→  AUTHENTICATION: 'authentication',
    31→
    32→  // UI & Components
    33→  WIDGET: 'widget',
    34→  RENDER: 'render',
    35→
    36→  // Network
    37→  NETWORK: 'network',
    38→  API: 'api',
    39→
    40→  // General
    41→  VALIDATION: 'validation',
    42→  UNKNOWN: 'unknown',
    43→} as const;
    44→
    45→export type ErrorCategory = (typeof ErrorCategory)[keyof typeof ErrorCategory];
    46→
    47→/**
    48→ * Error severity levels
    49→ */
    50→export const ErrorSeverity = {
    51→  /** Informational - logged but not shown to user */
    52→  INFO: 'info',
    53→  /** Warning - shown briefly, operation continues */
    54→  WARNING: 'warning',
    55→  /** Error - shown to user, operation failed but app continues */
    56→  ERROR: 'error',
    57→  /** Critical - shown prominently, may require user action */
    58→  CRITICAL: 'critical',
    59→} as const;
    60→
    61→export type ErrorSeverity = (typeof ErrorSeverity)[keyof typeof ErrorSeverity];
    62→
    63→/**
    64→ * Structured application error
    65→ */
    66→export interface AppError {
    67→  /** Unique error ID for tracking */
    68→  id: string;
    69→  /** Error category for routing/handling */
    70→  category: ErrorCategory;
    71→  /** Severity level */
    72→  severity: ErrorSeverity;
    73→  /** Technical error message (for logs) */
    74→  message: string;
    75→  /** User-friendly message (for display) */
    76→  userMessage: string;
    77→  /** Original error if wrapped */
    78→  originalError?: Error;
    79→  /** Additional context */
    80→  context?: Record<string, unknown>;
    81→  /** Suggested recovery action */
    82→  recoveryAction?: string;
    83→  /** Timestamp */
    84→  timestamp: Date;
    85→  /** Whether error was reported to user */
    86→  reported: boolean;
    87→}
    88→
    89→/**
    90→ * Error listener callback type
    91→ */
    92→type ErrorListener = (error: AppError) => void;
    93→
    94→/**
    95→ * Error service configuration
    96→ */
    97→interface ErrorServiceConfig {
    98→  /** Enable console logging in development */
    99→  enableConsoleLogging: boolean;
   100→  /** Maximum errors to keep in history */
   101→  maxHistorySize: number;
   102→  /** Auto-dismiss timeout for non-critical errors (ms) */
   103→  autoDismissTimeout: number;
   104→}
   105→
   106→/**
   107→ * Default user-friendly messages by category
   108→ */
   109→const DEFAULT_USER_MESSAGES: Record<ErrorCategory, string> = {
   110→  [ErrorCategory.STORAGE]: 'Unable to save your data. Please try again.',
   111→  [ErrorCategory.INDEXEDDB]: 'Database error. Your data may not be saved.',
   112→  [ErrorCategory.PERSISTENCE]: 'Failed to persist changes.',
   113→  [ErrorCategory.AI_PROVIDER]: 'AI service temporarily unavailable.',
   114→  [ErrorCategory.AI_RATE_LIMIT]: 'Too many requests. Please wait a moment.',
   115→  [ErrorCategory.AI_QUOTA]: 'API quota exceeded. Check your usage limits.',
   116→  [ErrorCategory.AI_NETWORK]: 'Cannot connect to AI service. Check your internet.',
   117→  [ErrorCategory.ENCRYPTION]: 'Encryption error. Please verify your password.',
   118→  [ErrorCategory.AUTHENTICATION]: 'Authentication failed. Please try again.',
   119→  [ErrorCategory.WIDGET]: 'Widget failed to load. Try refreshing.',
   120→  [ErrorCategory.RENDER]: 'Display error occurred.',
   121→  [ErrorCategory.NETWORK]: 'Network error. Check your connection.',
   122→  [ErrorCategory.API]: 'Service request failed.',
   123→  [ErrorCategory.VALIDATION]: 'Invalid input provided.',
   124→  [ErrorCategory.UNKNOWN]: 'An unexpected error occurred.',
   125→};
   126→
   127→/**
   128→ * Recovery suggestions by category
   129→ */
   130→const RECOVERY_SUGGESTIONS: Record<ErrorCategory, string> = {
   131→  [ErrorCategory.STORAGE]: 'Try clearing browser cache or using a different browser.',
   132→  [ErrorCategory.INDEXEDDB]: 'Refresh the page. If issue persists, export and reimport your data.',
   133→  [ErrorCategory.PERSISTENCE]: 'Your changes are saved locally. They will sync when connection is restored.',
   134→  [ErrorCategory.AI_PROVIDER]: 'Try switching to a different AI provider in settings.',
   135→  [ErrorCategory.AI_RATE_LIMIT]: 'Wait 30 seconds before trying again.',
   136→  [ErrorCategory.AI_QUOTA]: 'Upgrade your plan or switch to a free provider.',
   137→  [ErrorCategory.AI_NETWORK]: 'Check your internet connection and try again.',
   138→  [ErrorCategory.ENCRYPTION]: 'Re-enter your encryption password.',
   139→  [ErrorCategory.AUTHENTICATION]: 'Log out and log back in.',
   140→  [ErrorCategory.WIDGET]: 'Remove and re-add the widget.',
   141→  [ErrorCategory.RENDER]: 'Refresh the page.',
   142→  [ErrorCategory.NETWORK]: 'Check your internet connection.',
   143→  [ErrorCategory.API]: 'Try again in a few moments.',
   144→  [ErrorCategory.VALIDATION]: 'Check your input and try again.',
   145→  [ErrorCategory.UNKNOWN]: 'Refresh the page. If issue persists, contact support.',
   146→};
   147→
   148→/**
   149→ * Generate unique error ID
   150→ */
   151→function generateErrorId(): string {
   152→  return `err_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
   153→}
   154→
   155→/**
   156→ * Centralized Error Service
   157→ */
   158→class ErrorService {
   159→  private config: ErrorServiceConfig;
   160→  private listeners: Set<ErrorListener> = new Set();
   161→  private errorHistory: AppError[] = [];
   162→  private isDevelopment: boolean;
   163→
   164→  constructor() {
   165→    this.isDevelopment = import.meta.env.DEV;
   166→    this.config = {
   167→      enableConsoleLogging: this.isDevelopment,
   168→      maxHistorySize: 100,
   169→      autoDismissTimeout: 5000,
   170→    };
   171→  }
   172→
   173→  /**
   174→   * Update service configuration
   175→   */
   176→  configure(config: Partial<ErrorServiceConfig>): void {
   177→    this.config = { ...this.config, ...config };
   178→  }
   179→
   180→  /**
   181→   * Subscribe to error events
   182→   */
   183→  subscribe(listener: ErrorListener): () => void {
   184→    this.listeners.add(listener);
   185→    return () => this.listeners.delete(listener);
   186→  }
   187→
   188→  /**
   189→   * Create and handle an error
   190→   */
   191→  handleError(
   192→    category: ErrorCategory,
   193→    message: string,
   194→    options: {
   195→      severity?: ErrorSeverity;
   196→      userMessage?: string;
